{"new_string": "switch_to_gemini() {
    echo "🟣 切换到 Gemini（视觉分析）..."

    sed -i '' "s/^  provider:.*/  provider: gemini/" "$CONFIG"
    sed -i '' "s/^  default:.*/  default: $GEMINI_MODEL/" "$CONFIG"
    sed -i '' 's|^  base_url:.*|  base_url: '\"$GEMINI_BASE_URL\"'|' "$CONFIG"
    sed -i '' "s/^  max_context:.*/  max_context: $GEMINI_MAX_CONTEXT/" "$CONFIG"

    echo "✅ 已切换至 Gemini - $GEMINI_MODEL（1M上下文，支持视觉）"
}

